#include<bits/stdc++.h>
using namespace std;
long long dfn[100010],fa[100010],d[100010],siz[100010],son[100010],top[100010],dfncnt,val[100010],rnk[100010];
vector<long long> mp[100010];
void dfs1(long long x,long long f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(long long i:mp[x])
    {
        if(i!=f)
        {
            fa[i]=x;
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
set<long long> s[100010];
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(long long i:mp[x])
        {
            if(i!=son[x]&&i!=fa[x])
            {
                dfs2(i,i);
            }
        }
    }
}
long long col[100010];
int main()
{
    long long n,q;
    scanf("%lld%lld",&n,&q);
    for(long long i=1;i<n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs1(1);
    dfs2(1,1);
    while(q--)
    {
        long long op,x;
        scanf("%lld%lld",&op,&x);
        if(op==0)
        {
            col[x]^=1;
            if(col[x]==1)
            {
                s[top[x]].insert(dfn[x]);
            }
            else
            {
                s[top[x]].erase(dfn[x]);
            }
        }
        else
        {
            long long ans=-1;
            while(x)
            {
                long long y=(*s[top[x]].begin());
                if(!s[top[x]].empty()&&d[rnk[y]]<=d[x])
                {
                    ans=rnk[y];
                }
                x=fa[top[x]];
            }
            printf("%lld\n",ans);
        }
    }
    return 0;
}
